mapper.select:
SELECT COUNT(1)
FROM USER_AUTHENTICATION
WHERE USER_AUTH_ID = #{value}

mapper.update:
UPDATE USER_AUTHENTICATION ua
SET ua.USER_AUTH_PW = #{encodedPassword}
WHERE ua.USER_AUTH_ID = #{userId}
  AND LOWER(ua.USER_AUTH_EMAIL) = LOWER(#{email})
  AND EXISTS (
        SELECT 1
        FROM USERS u
        WHERE u.USER_NO = ua.USER_NO
          AND u.USER_STATUS = #{activeStatus}
  )

UPDATE USERS u
SET u.USER_PHONENUMBER = #{userPhoneNumber},
    u.USER_REGISTRATION_NO = #{userRegistrationNo},
    u.USER_UPDATED_AT = SYSTIMESTAMP
WHERE u.USER_STATUS = #{activeStatus}
  AND EXISTS (
        SELECT 1
        FROM USER_AUTHENTICATION ua
        WHERE ua.USER_NO = u.USER_NO
          AND ua.USER_AUTH_ID = #{userId}
          AND NVL(ua.USER_AUTH_SNS_TYPE, #{defaultSnsType}) != #{defaultSnsType}
  )
